def validate_signature(payload_body: bytes, signature_header: str) -> bool:
    """Validate the webhook signature using HMAC-SHA256."""
    if not WEBHOOK_SECRET:
        logger.warning("WEBHOOK_SECRET is not configured. Skipping signature validation.")
        return False

    if not signature_header:
        logger.warning("No signature header provided.")
        return False

    # Support multiple signature formats
    # Format: sha256=<hex_digest> or just <hex_digest>
    if signature_header.startswith("sha256="):
        received_signature = signature_header[7:]
    else:
        received_signature = signature_header

    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode("utf-8"),
        payload_body,
        hashlib.sha256,
    ).hexdigest()

    return hmac.compare_digest(expected_signature, received_signature)


def validate_ip(request) -> bool:
    """Validate the request originates from an allowed IP address."""
    if not ALLOWED_IPS or ALLOWED_IPS == [""]:
        # No IP restriction configured
        return True

    # Check X-Forwarded-For header (Cloud Functions behind load balancer)
    forwarded_for = request.headers.get("X-Forwarded-For", "")
    if forwarded_for:
        client_ip = forwarded_for.split(",")[0].strip()
    else:
        client_ip = request.remote_addr

    if client_ip in ALLOWED_IPS:
        return True

    logger.warning(f"Request from unauthorized IP: {client_ip}")
    return False


def validate_partner_id(partner_id: str) -> bool:
    """Validate the partner ID is in the allowed list."""
    if not ALLOWED_PARTNER_IDS or ALLOWED_PARTNER_IDS == [""]:
        # No partner restriction configured
        return True

    if partner_id in ALLOWED_PARTNER_IDS:
        return True

    logger.warning(f"Request from unauthorized partner: {partner_id}")
    return False


def validate_payload(payload: dict) -> tuple[bool, str]:
    """Validate the webhook payload structure and content."""
    required_fields = ["event_type", "partner_id", "timestamp", "data"]

    for field in required_fields:
        if field not in payload:
            return False, f"Missing required field: {field}"

    # Validate event type
    event_type = payload.get("event_type")
    if event_type not in SUPPORTED_EVENTS:
        return False, f"Unsupported event type: {event_type}"

    # Validate timestamp (reject events older than 5 minutes to prevent replay attacks)
    try:
        event_timestamp = datetime.fromisoformat(payload["timestamp"].replace("Z", "+00:00"))
        now = datetime.now(timezone.utc)
        time_diff = abs((now - event_timestamp).total_seconds())
        if time_diff > 300:  # 5 minutes
            return False, f"Event timestamp too old or too far in the future: {time_diff}s difference"
    except (ValueError, TypeError) as e:
        return False, f"Invalid timestamp format: {e}"

    # Validate data field based on event type
    data = payload.get("data", {})
    if not isinstance(data, dict):
        return False, "Data field must be a JSON object"

    # Payment events require transaction_id and amount
    if event_type.startswith("payment."):
        if "transaction_id" not in data:
            return False, "Payment events require transaction_id in data"
        if "amount" not in data:
            return False, "Payment events require amount in data"
        if "currency" not in data:
            return False, "Payment events require currency in data"

        # Validate amount is a positive number
        try:
            amount = float(data["amount"])
            if amount < 0:
                return False, "Amount must be non-negative"
        except (ValueError, TypeError):
            return False, "Amount must be a valid number"

    # Subscription events require subscription_id
    if event_type.startswith("subscription."):
        if "subscription_id" not in data:
            return False, "Subscription events require subscription_id in data"

    # Dispute events require dispute_id
    if event_type.startswith("dispute."):
        if "dispute_id" not in data:
            return False, "Dispute events require dispute_id in data"

    return True, "Valid"


