@functions_framework.http
def payment_webhook(request):
    """
    HTTP Cloud Function endpoint for processing payment webhook events.

    Deploy with:
        gcloud functions deploy payment-webhook \
            --gen2 \
            --runtime=python312 \
            --region=us-central1 \
            --source=. \
            --entry-point=payment_webhook \
            --trigger-http \
            --allow-unauthenticated \
            --set-env-vars="WEBHOOK_SECRET=your-secret-here,ALLOWED_PARTNER_IDS=partner1,partner2,ALLOWED_IPS=203.0.113.1,203.0.113.2" \
            --memory=256MB \
            --timeout=60s

    Expected request format:
        POST with JSON body:
        {
            "event_id": "evt_abc123",
            "event_type": "payment.completed",
            "partner_id": "partner1",
            "timestamp": "2024-01-15T10:30:00Z",
            "data": {
                "transaction_id": "txn_xyz789",
                "amount": 99.99,
                "currency": "USD",
                "customer_id": "cust_456",
                ...
            }
        }

    Headers:
        X-Webhook-Signature: sha256=<hmac_hex_digest>
        Content-Type: application/json
    """

    # Only allow POST requests
    if request.method != "POST":
        logger.warning(f"Rejected {request.method} request")
        return (
            json.dumps({"error": "Method not allowed. Use POST."}),
            405,
            {"Content-Type": "application/json"},
        )

    # Validate Content-Type
    content_type = request.headers.get("Content-Type", "")
    if "application/json" not in content_type:
        logger.warning(f"Rejected request with Content-Type: {content_type}")
        return (
            json.dumps({"error": "Content-Type must be application/json"}),
            415,
            {"Content-Type": "application/json"},
        )

    # Validate IP address
    if not validate_ip(request):
        return (
            json.dumps({"error": "Forbidden"}),
            403,
            {"Content-Type": "application/json"},
        )

    # Get raw request body for signature validation
    raw_body = request.get_data()

    if not raw_body:
        return (
            json.dumps({"error": "Empty request body"}),
            400,
            {"Content-Type": "application/json"},
        )

    # Validate webhook signature
    signature = request.headers.get("X-Webhook-Signature", "")
    if WEBHOOK_SECRET:
        if not validate_signature(raw_body, signature):
            logger.warning("Invalid webhook signature")
            return (
                json.dumps({"error": "Invalid signature"}),
                401,
                {"Content-Type": "application/json"},
            )
    else:
        logger.warning("WEBHOOK_SECRET not configured - signature validation skipped")

    # Parse JSON body
    try:
        payload = json.loads(raw_body)
    except json.JSONDecodeError as e:
        logger.warning(f"Invalid JSON payload: {e}")
        return (
            json.dumps({"error": "Invalid JSON payload"}),
            400,
            {"Content-Type": "application/json"},
        )

    # Validate payload structure
    is_valid, validation_message = validate_payload(payload)
    if not is_valid:
        logger.warning(f"Payload validation failed: {validation_message}")
        return (
            json.dumps({"error": validation_message}),
            400,
            {"Content-Type": "application/json"},
        )

    # Validate partner ID
    partner_id = payload.get("partner_id", "")
    if not validate_partner_id(partner_id):
        return (
            json.dumps({"error": "Unauthorized partner"}),
            403,
            {"Content-Type": "application/json"},
        )

    # Idempotency check
    event_id = payload.get("event_id", "")
    if event_id and check_idempotency(event_id):
        logger.info(f"Duplicate event detected: {event_id}")
        return (
            json.dumps({
                "status": "already_processed",
                "event_id": event_id,
                "message": "This event has already been processed",
            }),
            200,
            {"Content-Type": "application/json"},
        )

    # Process the event
    event_type = payload["event_type"]
    data = payload["data"]

    try:
        result = route_event(event_type, data, partner_id)

        logger.info(
            f"Successfully processed webhook: event_id={event_id}, "
            f"event_type={event_type}, partner={partner_id}"
        )

        response = {
            "status": "success",
            "event_id": event_id,
            "event_type": event_type,
            "result": result,
            "processed_at": datetime.now(timezone.utc).isoformat(),
        }

        return (
            json.dumps(response),
            200,
            {"Content-Type": "application/json"},
        )

    except Exception as e:
        logger.error(
            f"Error processing webhook: event_id={event_id}, "
            f"event_type={event_type}, error={str(e)}",
            exc_info=True,
        )

        # Return 500 so the payment partner will retry
        return (
            json.dumps({
                "status": "error",
                "event_id": event_id,
                "message": "Internal processing error. Please retry.",
            }),
            500,
            {"Content-Type": "application/json"},
        )